mapper.select:
/* UserSavingMapper.selectSavingList */ SELECT SI_SEQ AS siSeq ,SI_SJ AS siSj ,SI_TOTAL_AMOUNT AS siTotalAmount ,MONTHLY_PAYMENT_AMOUNT AS monthlyPaymentAmount ,MONTHLY_PAYMENT_AMOUNT * PAY_CNT AS payAmount ,TRAN_DAY AS tranDay ,BEGIN_DE AS beginDe ,END_DE AS endDe ,PAY_CNT AS payCnt ,REG_DT AS regDt FROM TB_SAVING_INFO WHERE MEMBER_ID = #{userId} AND DEL_YN = 'N'
AND SI_SJ LIKE CONCAT('%', #{siSj}, '%')
ORDER BY REG_DT DESC LIMIT #{offset}, #{pageSize}

mapper.insert:
/* UserSavingMapper.insertSaving */
INSERT INTO TB_SAVING_INFO (
	 MEMBER_ID
	,SI_SEQ
	,SI_SJ
	,BEGIN_DE
	,END_DE
	,SI_TOTAL_AMOUNT
	,MONTHLY_PAYMENT_AMOUNT
	,TRAN_DAY
	,PAY_CNT
	,DEL_YN
	,REG_ID
	,REG_DT
	,UPD_ID
	,UPD_DT
) VALUES (
	 #{userId}
	,#{siSeq}
	,#{siSj}
	,#{beginDe}
	,#{endDe}
	,REPLACE(#{siTotalAmount}, ',', '')
	,REPLACE(#{monthlyPaymentAmount}, ',', '')
	,#{tranDay}
	,#{payCnt}
	,'N'
	,#{userId}
	,now()
	,#{userId}
	,now()
)

mapper.update:
/* UserSavingMapper.updateSaving */
UPDATE
	TB_SAVING_INFO
SET
	 SI_SJ					= #{siSj}
	,BEGIN_DE				= #{beginDe}
	,END_DE					= #{endDe}
	,SI_TOTAL_AMOUNT		= REPLACE(#{siTotalAmount}, ',', '')
	,MONTHLY_PAYMENT_AMOUNT	= REPLACE(#{monthlyPaymentAmount}, ',', '')
	,TRAN_DAY				= #{tranDay}
	,PAY_CNT				= #{payCnt}
	,UPD_ID					= #{userId}
	,UPD_DT					= now()
WHERE
	MEMBER_ID = #{userId}
AND
	SI_SEQ = #{siSeq}

/* UserSavingMapper.deleteSaving */
UPDATE
	TB_SAVING_INFO
SET
	 DEL_YN = 'N'
	,UPD_ID	= #{userId}
	,UPD_DT	= now()
WHERE
	MEMBER_ID = #{userId}
AND
	SI_SEQ = #{siSeq}

/* UserSavingMapper.updateSchedulerSaving */
UPDATE
	TB_SAVING_INFO
SET
	PAY_CNT = PAY_CNT + 1
WHERE
	MEMBER_ID = #{userId}
AND
	SI_SEQ = #{siSeq}
